use std::collections::{HashMap, VecDeque};

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut adj = HashMap::new();

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let start = edge[2] as i64;
        let end = edge[3] as i64;
        adj.entry(u).or_insert_with(Vec::new).push((v, (start, end)));
    }

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    let mut pq = std::collections::BinaryHeap::new();
    pq.push((0, 0));

    while let Some((time, node)) = pq.pop() {
        if node == n - 1 {
            return time;
        }
        if time > dist[node] {
            continue;
        }

        // Try to stay at current node
        if time < dist[node] {
            dist[node] = time;
            pq.push((time, node));
        }

        // Try to take each outgoing edge
        if let Some(edges) = adj.get(&node) {
            for (v, (start, end)) in edges {
                if start <= time as i64 && time as i64 <= end {
                    let new_time = time + 1;
                    if new_time < dist[*v] {
                        dist[*v] = new_time;
                        pq.push((new_time, *v));
                    }
                }
            }
        }
    }

    -1
}
